pragma solidity ^0.8.20;

contract GrandGooseMansion {
    address private _owner;
    uint256 public supply;
    uint256 public cost;
    uint256 public maxSupply;
    uint256 public preSaleWalletLimit;
    mapping(address => uint256) private _preSaleWalletMinted;
    mapping(address => bool) private _whitelist;
    enum SaleStatus { Paused, Presale, PublicSale }
    SaleStatus private _currentSaleStatus = SaleStatus.Paused;

    constructor() {
        _owner = msg.sender;
        maxSupply = 10000; // Example value, adjust as needed
        preSaleWalletLimit = 10; // Example value, adjust as needed
    }

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not the owner");
        _;
    }

    function isWhitelisted(address user) public view returns (bool) {
        return _whitelist[user];
    }

    function whitelistUser(address user, bool status) public onlyOwner {
        _whitelist[user] = status;
    }

    function startPresale() public onlyOwner {
        _currentSaleStatus = SaleStatus.Presale;
    }

    function startPublicSale() public onlyOwner {
        _currentSaleStatus = SaleStatus.PublicSale;
    }

    function setCost(uint256 newCost) public onlyOwner {
        cost = newCost;
    }

    function mintTokenWhitelisted(uint256 amount) public payable {
        require(_currentSaleStatus == SaleStatus.Presale, "Presale not active");
        require(_whitelist[msg.sender], "Not whitelisted");
        require(amount > 0, "Amount must be greater than 0");
        require(supply + amount <= maxSupply, "Exceeds max supply");
        require(_preSaleWalletMinted[msg.sender] + amount <= preSaleWalletLimit, "Exceeds wallet limit");
        require(msg.value == cost * amount, "Incorrect payment");

        supply += amount;
        _preSaleWalletMinted[msg.sender] += amount;
    }

    function mintTokenPublic(uint256 amount) public payable {
        require(_currentSaleStatus == SaleStatus.PublicSale, "Public sale not active");
        require(amount > 0, "Amount must be greater than 0");
        require(supply + amount <= maxSupply, "Exceeds max supply");
        require(msg.value == cost * amount, "Incorrect payment");

        supply += amount;
    }

    function preSaleWalletMinted(address user) public view returns (uint256) {
        return _preSaleWalletMinted[user];
    }

    function currentSaleStatus() public view returns (SaleStatus) {
        return _currentSaleStatus;
    }
}
